package com.vidaysalud.veterinaria.inventarioservicio.model;import jakarta.persistence.*;import lombok.*;import java.time.LocalDateTime;@Entity @Table(name="movimiento_inventario") @Getter @Setter @NoArgsConstructor @AllArgsConstructor @Builder public class MovimientoInventario{@Id @GeneratedValue(strategy=GenerationType.IDENTITY)@Column(name="id_movimiento")private Integer idMovimiento;@Column(name="id_medicamento",nullable=false)private Integer idMedicamento;@Enumerated(EnumType.STRING)@Column(name="tipo_movimiento",nullable=false)private TipoMovimiento tipoMovimiento;@Column(nullable=false)private Integer cantidad;@Column(name="stock_anterior",nullable=false)private Integer stockAnterior;@Column(name="stock_posterior",nullable=false)private Integer stockPosterior;@Column(name="fecha_movimiento",nullable=false,updatable=false)private LocalDateTime fechaMovimiento;@Column(length=255)private String motivo;@PrePersist void pre(){if(fechaMovimiento==null)fechaMovimiento=LocalDateTime.now();}}